public class DebugRotation {
    public static void main(String[] args) {
        double u1x = -1321008684645961.0 /  268435456.0;
        double u1y = -5774608829631843.0 /  268435456.0;
        double u1z = -3822921525525679.0 / 4294967296.0;

        double u2x = -5712344449280879.0 /    2097152.0;
        double u2y = -2275058564560979.0 /    1048576.0;
        double u2z =  4423475992255071.0 /      65536.0;

        double u1u1 = u1x*u1x + u1y*u1y + u1z*u1z;
        double u2u2 = u2x*u2x + u2y*u2y + u2z*u2z;
        double u1u2 = u1x*u2x + u1y*u2y + u1z*u2z;

        double coeffU = u1u2 / u1u1;
        double diff = u2u2 - u1u2 * coeffU;

        System.out.println("u1u1: " + u1u1);
        System.out.println("u2u2: " + u2u2);
        System.out.println("u1u2: " + u1u2);
        System.out.println("coeffU: " + coeffU);
        System.out.println("u2u2 - u1u2 * coeffU: " + diff);

        // Check the v side
        double v1x = 1.0;
        double v1y = 0.0;
        double v1z = 0.0;

        double v2x = 0.0;
        double v2y = 0.0;
        double v2z = 1.0;

        // v1 is normalized in the code to match u1u1
        // v1_new = sqrt(u1u1 / v1v1) * v1
        double v1v1 = v1x*v1x + v1y*v1y + v1z*v1z;
        double scale = Math.sqrt(u1u1 / v1v1);
        double v1nx = v1x * scale;
        double v1ny = v1y * scale;
        double v1nz = v1z * scale;

        double v1v2 = v1nx*v2x + v1ny*v2y + v1nz*v2z; // Should be 0
        double coeffV = v1v2 / u1u1; // Should be 0

        double v2v2 = v2x*v2x + v2y*v2y + v2z*v2z;

        double diffV = v2v2 - v1v2 * coeffV;
        System.out.println("diffV: " + diffV);

        System.out.println("Ratio: " + (diff / diffV));
        System.out.println("Sqrt: " + Math.sqrt(diff / diffV));

    }
}

